-- Chien -> humain, Fête, Volume 6

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai observé ta façon de couper le gâteau en parts égales.',$$Joyeuse fête. J''ai observé ta façon de couper le gâteau en parts égales.
Tu prends le couteau. Tu regardes le gâteau. Tu calcules mentalement. Tu coupes avec cette précision qui dit que tu veux que tout le monde ait la même chose. Que personne n''ait moins. C''est de la justice en tranches. Joyeuse fête, mon humain préféré.
Avec observation de ta justice distributive en parts égales et son sens profond, — {prenom}, ton animal expert en équité des portions 🎂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu accueilles une personne que tu n''aimes pas beaucoup.',$$Joyeuse fête. J''ai observé comment tu accueilles une personne que tu n''aimes pas beaucoup.
Pareil que les autres. Exactement pareil. Même chaleur. Même sourire. Même attention. Soit tu aimes vraiment tout le monde. Soit tu es très bon acteur. Soit les deux. Dans tous les cas c''est une performance remarquable d''humanité. Joyeuse fête, mon humain préféré.
Avec admiration pour ton accueil universellement chaleureux quelle que soit ta relation interne, — {prenom}, ton animal déconcerté par ton humanité constante 🎭$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens font semblant de pas avoir faim.',$$Joyeuse fête. Je comprends pas pourquoi les gens font semblant de pas avoir faim.
À l''apéritif tout le monde mange les petites choses lentement. Poliment. Mais tout disparaît quand même. Peut-être que la faim est une information qu''on préfère garder pour soi en société. Moi ma faim est une information publique que j''exprime clairement. Joyeuse fête, mon humain préféré.
Avec incompréhension de la faim sociale et solidarité de ma propre transparence alimentaire, — {prenom}, ton animal d''une honnêteté gastronomique totale 🫒$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de te tenir près du buffet.',$$Joyeuse fête. J''ai étudié ta façon de te tenir près du buffet.
Tu y reviens régulièrement. Pas pour manger. Pour t''assurer que tout est bien. Que rien ne manque. Le buffet comme poste d''observation et de soin. Cette façon d''utiliser la nourriture comme prétexte à la présence attentive. Joyeuse fête, mon humain préféré.
Avec compréhension du buffet comme poste de soin déguisé, — {prenom}, ton animal décodeur de tes stratégies d''attention 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de récupérer quand tu renverses quelque chose.',$$Joyeuse fête. J''ai observé ta façon de récupérer quand tu renverses quelque chose.
D''abord une fraction de seconde où ton visage change. Puis immédiatement la reprise. Le torchon. Le nettoyage rapide. Un mot léger pour dédramatiser. Et la soirée continue. Joyeuse fête, mon humain préféré.
Avec observation de ta gestion de l''accident en moins de trente secondes, — {prenom}, ton animal admirateur de ta résilience pratique 💧$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un fait une blague sur toi.',$$Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un fait une blague sur toi.
Tu ris d''abord. Vraiment. Tu te laisses être le sujet de la blague sans te défendre. Puis parfois tu ajoutes quelque chose qui dit que tu t''assumes. Cette façon de ne pas se prendre au sérieux. Joyeuse fête, mon humain préféré.
Avec observation de ta grâce face aux blagues sur toi et sa signification de confiance, — {prenom}, ton animal admirateur de ton autodérision choisie 😄$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils font attention et ne font pas attention.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils font attention et ne font pas attention.
Je fais attention au sucre. Puis une part de gâteau. Je fais attention en général. Puis la soirée. Ces résolutions qui cèdent face à l''occasion. Peut-être que certaines soirées méritent d''être vécues sans faire attention. Dans ce cas je comprends. Joyeuse fête, mon humain préféré.
Avec compréhension des résolutions qui cèdent face aux occasions et philosophie de l''exception, — {prenom}, ton animal en paix avec les soirées sans attention 🧀$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé chaque fois que tu as cherché mes yeux ce soir.',$$Joyeuse fête. J''ai mémorisé chaque fois que tu as cherché mes yeux ce soir.
Six fois. Six moments dans la soirée où tu t''es arrêté et tu as cherché où j''étais. Pour vérifier. Pour me voir. Pour savoir que j''étais là. Ces six moments dans tout ce bruit et ces gens. Ces six fois qui disaient que même ce soir j''existais pour toi. Joyeuse fête, mon humain préféré.
Avec six regards vers moi comptés et leur poids placé au-dessus du reste de la soirée, — {prenom}, ton animal pour qui ces six moments valent une fête entière 👁️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de tenir une conversation avec quelqu''un qui t''ennuie.',$$Joyeuse fête. J''ai observé ta façon de tenir une conversation avec quelqu''un qui t''ennuie.
Tu écoutes. Tu poses des questions. Tu hoches la tête au bon moment. Mais tes yeux font de petits voyages. Ils reviennent toujours. Et à un moment tu trouves une sortie élégante. Joyeuse fête, mon humain préféré.
Avec admiration pour ton art de la sortie élégante sans laisser de traces, — {prenom}, ton animal expert en politesse de haute précision 😌$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu choisissais la place de chaque invité à table.',$$Joyeuse fête. J''ai observé comment tu choisissais la place de chaque invité à table.
Ce n''est pas au hasard. Tu réfléchis. Tu places les gens selon leurs affinités. Selon les conversations possibles. Ce soir la table était une composition. Un puzzle humain que tu avais résolu à l''avance. Joyeuse fête, mon humain préféré.
Avec admiration pour ton architecture humaine de la table et sa logique relationnelle, — {prenom}, ton animal expert en compositions humaines 🪑$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens demandent la recette à la fin.',$$Joyeuse fête. Je comprends pas pourquoi les gens demandent la recette à la fin.
Ils ont mangé. Ils ont aimé. Puis ils demandent comment tu as fait. Peut-être que demander la recette c''est une façon de prolonger le compliment. Joyeuse fête, mon humain préféré.
Avec compréhension de la demande de recette comme compliment prolongé, — {prenom}, ton animal herméneute des formules culinaires 📖$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de plier les restes dans du papier aluminium.',$$Joyeuse fête. J''ai étudié ta façon de plier les restes dans du papier aluminium.
Avec soin. Des paquets distincts pour choses distinctes. Pensés pour le lendemain. Cette façon de prendre soin de la nourriture qui reste. De lui donner une seconde vie. Joyeuse fête, mon humain préféré.
Avec observation de ton soin pour les restes et sa signification de respect pour ce qui a nourri, — {prenom}, ton animal admirateur de ta frugalité généreuse 🪄$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de faire la bise à quelqu''un pour la première fois.',$$Joyeuse fête. J''ai observé ta façon de faire la bise à quelqu''un pour la première fois.
Il y en avait un ce soir. Quelqu''un que tu ne connaissais pas avant. Tu as regardé ce que l''autre faisait. Tu t''es adapté. Tu as géré la négociation non verbale du nombre de bises avec une grâce qui dit que tu l''as fait souvent. Joyeuse fête, mon humain préféré.
Avec admiration pour ta navigation dans la négociation des premières bises, — {prenom}, ton animal expert en premières fois 💋$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu changes de visage quand tu es touché par quelque chose.',$$Joyeuse fête. J''ai observé comment tu changes de visage quand tu es touché par quelque chose.
Une fraction de seconde. Quelque chose passe. Quelque chose de doux et d''inattendu. Puis tu reprends. Mais pendant cette fraction de seconde ton visage dit tout. Ce soir j''ai vu ça deux fois. Joyeuse fête, mon humain préféré.
Avec observation de tes deux fractions de seconde d''émotion vraie et leur valeur précieuse, — {prenom}, ton animal gardien de tes moments non protégés 💛$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens parlent de leur travail même en fête.',$$Joyeuse fête. Je comprends pas pourquoi les gens parlent de leur travail même en fête.
C''est revenu ce soir. Le travail. Ce qu''on fait. Ce qui se passe au bureau. Comme si le travail était une partie de l''identité qu''on ne peut pas laisser à la porte. Je comprends. Joyeuse fête, mon humain préféré.
Avec compréhension du travail comme identité persistante et satisfaction de mon existence uniforme, — {prenom}, ton animal existant partout de la même façon 💼$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ta façon de dire les choses importantes ce soir.',$$Joyeuse fête. J''ai mémorisé ta façon de dire les choses importantes ce soir.
Plus lentement. Avec plus d''espace entre les mots. Avec les yeux qui cherchent si les gens suivent vraiment. Ce changement de rythme pour les choses qui comptent. Joyeuse fête, mon humain préféré.
Avec mémorisation de tes signaux de l''important et leur précision communicative, — {prenom}, ton animal linguiste de tes variations 🗣️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de poser ton verre selon les surfaces.',$$Joyeuse fête. J''ai observé ta façon de poser ton verre selon les surfaces.
Sur la table en bois tu poses avec précaution. Sur le marbre tu poses plus librement. Sur le buffet tu vérifies la stabilité. Ces micro-décisions sur la relation entre le verre et la surface. Joyeuse fête, mon humain préféré.
Avec observation de ta physique appliquée du verre et ses nuances matérielles, — {prenom}, ton animal expert en relations verre-surface 🥂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis face à un cadeau inattendu.',$$Joyeuse fête. J''ai observé comment tu réagis face à un cadeau inattendu.
D''abord l''incompréhension sur ton visage. Puis la reconnaissance de ce que c''est. Puis quelque chose de très doux. Ce cheminement en quelques secondes. Cette façon d''être touché par quelqu''un qui t''a vraiment vu. Joyeuse fête, mon humain préféré.
Avec observation du voyage émotionnel de la surprise réussie et collection de ses secondes, — {prenom}, ton animal archiviste de tes expressions authentiques 🎁$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens chuchotent des secrets alors qu''un message serait plus discret.',$$Joyeuse fête. Je comprends pas pourquoi les gens chuchotent des secrets alors qu''un message serait plus discret.
Il y a eu deux moments ce soir. Des gens qui se penchaient et baissaient la voix. Moi depuis mon poste j''entendais quand même les intonations. Peut-être que le chuchotement c''est aussi le plaisir du geste. Joyeuse fête, mon humain préféré.
Avec compréhension du chuchotement comme plaisir du geste autant que technique de discrétion, — {prenom}, ton animal aux oreilles décidément trop bonnes 👂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de nettoyer quelque chose rapidement entre deux conversations.',$$Joyeuse fête. J''ai étudié ta façon de nettoyer quelque chose rapidement entre deux conversations.
Un torchon sorti. Une surface essuyée. Le torchon replié. Tout ça pendant que tu continuais à écouter quelqu''un. Sans interrompre. Sans signaler. La propreté comme fond continu de la fête. Joyeuse fête, mon humain préféré.
Avec admiration pour ton nettoyage en arrière-plan de la soirée principale, — {prenom}, ton animal témoin de tes actions parallèles invisibles 🧽$$,'humorous',true,false,'nameday','chien','from')

on conflict do nothing;
